class Solution:
    def kSimilarity(self, s1, s2):
        # Brute BFS that considers every swap of the first mismatched index
        # with any later index, exploring level by level.
        from collections import deque
        if s1 == s2:
            return 0
        start = s1
        seen = {start}
        q = deque([start])
        k = 0
        while q:
            k += 1
            for _ in range(len(q)):
                cur = q.popleft()
                i = 0
                while cur[i] == s2[i]:
                    i += 1
                for j in range(i + 1, len(cur)):
                    if cur[j] == s2[i] and cur[j] != s2[j]:
                        nxt = list(cur)
                        nxt[i], nxt[j] = nxt[j], nxt[i]
                        nxt = ''.join(nxt)
                        if nxt == s2:
                            return k
                        if nxt not in seen:
                            seen.add(nxt)
                            q.append(nxt)
        return k

