class Solution:
    def kSimilarity(self, s1, s2):
        from collections import deque
        q = deque([(s1, 0)])
        seen = {s1}
        while q:
            cur, swaps = q.popleft()
            if cur == s2:
                return swaps
            i = 0
            while cur[i] == s2[i]:
                i += 1
            for j in range(i + 1, len(cur)):
                if cur[j] == s2[i] and cur[j] != s2[j]:
                    lst = list(cur)
                    lst[i], lst[j] = lst[j], lst[i]
                    nxt = ''.join(lst)
                    if nxt not in seen:
                        seen.add(nxt)
                        q.append((nxt, swaps + 1))
        return 0

