var kSimilarity = function(s1, s2) {
    const queue = [[s1, 0]];
    const seen = new Set([s1]);
    let head = 0;
    while (head < queue.length) {
        const [cur, swaps] = queue[head++];
        if (cur === s2) return swaps;
        let i = 0;
        while (cur[i] === s2[i]) i++;
        for (let j = i + 1; j < cur.length; j++) {
            if (cur[j] === s2[i] && cur[j] !== s2[j]) {
                const arr = cur.split('');
                [arr[i], arr[j]] = [arr[j], arr[i]];
                const nxt = arr.join('');
                if (!seen.has(nxt)) {
                    seen.add(nxt);
                    queue.push([nxt, swaps + 1]);
                }
            }
        }
    }
    return 0;
};
